class DocumentLoader:
    """Loads and chunks documents from various sources."""

    SUPPORTED_EXTENSIONS = {".txt", ".md", ".json", ".csv", ".py", ".html", ".pdf"}

    def __init__(self, chunk_size: int = 500, chunk_overlap: int = 100):
        self.chunk_size = chunk_size
        self.chunk_overlap = chunk_overlap

    def load_directory(self, directory_path: str) -> List[Dict]:
        """Load all supported documents from a directory."""
        documents = []
        path = Path(directory_path)

        if not path.exists():
            raise FileNotFoundError(f"Directory not found: {directory_path}")

        for file_path in path.rglob("*"):
            if file_path.suffix.lower() in self.SUPPORTED_EXTENSIONS:
                try:
                    docs = self.load_file(str(file_path))
                    documents.extend(docs)
                    print(f"  Loaded: {file_path.name} ({len(docs)} chunks)")
                except Exception as e:
                    print(f"  Error loading {file_path.name}: {e}")

        return documents

    def load_file(self, file_path: str) -> List[Dict]:
        """Load a single file and split into chunks."""
        path = Path(file_path)
        extension = path.suffix.lower()

        if extension == ".json":
            content = self._load_json(file_path)
        elif extension == ".csv":
            content = self._load_csv(file_path)
        elif extension == ".pdf":
            content = self._load_pdf(file_path)
        else:
            with open(file_path, "r", encoding="utf-8", errors="ignore") as f:
                content = f.read()

        chunks = self._split_text(content)

        documents = []
        for i, chunk in enumerate(chunks):
            doc_id = hashlib.md5(f"{file_path}_{i}".encode()).hexdigest()
            documents.append({
                "id": doc_id,
                "content": chunk,
                "metadata": {
                    "source": str(file_path),
                    "filename": path.name,
                    "chunk_index": i,
                    "total_chunks": len(chunks),
                    "file_type": extension,
                }
            })

        return documents

    def _load_json(self, file_path: str) -> str:
        with open(file_path, "r", encoding="utf-8") as f:
            data = json.load(f)
        return json.dumps(data, indent=2)

    def _load_csv(self, file_path: str) -> str:
        import csv
        rows = []
        with open(file_path, "r", encoding="utf-8") as f:
            reader = csv.reader(f)
            for row in reader:
                rows.append(", ".join(row))
        return "\n".join(rows)

    def _load_pdf(self, file_path: str) -> str:
        try:
            import PyPDF2
        except ImportError:
            os.system("pip install PyPDF2")
            import PyPDF2

        text_parts = []
        with open(file_path, "rb") as f:
            reader = PyPDF2.PdfReader(f)
            for page in reader.pages:
                text = page.extract_text()
                if text:
                    text_parts.append(text)
        return "\n".join(text_parts)

    def _split_text(self, text: str) -> List[str]:
        """Split text into overlapping chunks."""
        if not text or not text.strip():
            return []

        # Clean the text
        text = text.strip()

        if len(text) <= self.chunk_size:
            return [text]

        chunks = []
        # Try to split on paragraph boundaries first
        paragraphs = text.split("\n\n")

        current_chunk = ""
        for paragraph in paragraphs:
            paragraph = paragraph.strip()
            if not paragraph:
                continue

            if len(current_chunk) + len(paragraph) + 2 <= self.chunk_size:
                current_chunk = (current_chunk + "\n\n" + paragraph).strip()
            else:
                if current_chunk:
                    chunks.append(current_chunk)
                # If single paragraph is too long, split by sentences
                if len(paragraph) > self.chunk_size:
                    sub_chunks = self._split_long_paragraph(paragraph)
                    chunks.extend(sub_chunks)
                    current_chunk = ""
                else:
                    current_chunk = paragraph

        if current_chunk:
            chunks.append(current_chunk)

        # Apply overlap
        if self.chunk_overlap > 0 and len(chunks) > 1:
            overlapped_chunks = [chunks[0]]
            for i in range(1, len(chunks)):
                prev_text = chunks[i - 1]
                overlap_text = prev_text[-self.chunk_overlap:] if len(prev_text) > self.chunk_overlap else prev_text
                # Find a word boundary in the overlap
                space_idx = overlap_text.find(" ")
                if space_idx != -1:
                    overlap_text = overlap_text[space_idx + 1:]
                overlapped_chunks.append(overlap_text + " " + chunks[i])
            chunks = overlapped_chunks

        return [c.strip() for c in chunks if c.strip()]

    def _split_long_paragraph(self, text: str) -> List[str]:
        """Split a long paragraph into chunks by sentences."""
        sentences = text.replace(". ", ".\n").split("\n")
        chunks = []
        current = ""

        for sentence in sentences:
            sentence = sentence.strip()
            if not sentence:
                continue
            if len(current) + len(sentence) + 1 <= self.chunk_size:
                current = (current + " " + sentence).strip()
            else:
                if current:
                    chunks.append(current)
                # If single sentence is still too long, force split
                if len(sentence) > self.chunk_size:
                    for j in range(0, len(sentence), self.chunk_size):
                        chunks.append(sentence[j:j + self.chunk_size])
                    current = ""
                else:
                    current = sentence

        if current:
            chunks.append(current)

        return chunks

    def load_text(self, text: str, source_name: str = "manual_input") -> List[Dict]:
        """Load raw text directly."""
        chunks = self._split_text(text)
        documents = []
        for i, chunk in enumerate(chunks):
            doc_id = hashlib.md5(f"{source_name}_{i}".encode()).hexdigest()
            documents.append({
                "id": doc_id,
                "content": chunk,
                "metadata": {
                    "source": source_name,
                    "filename": source_name,
                    "chunk_index": i,
                    "total_chunks": len(chunks),
                    "file_type": "text",
                }
            })
        return documents


class VectorStore:
    """Manages the vector database using ChromaDB and sentence-transformers."""

    def __init__(
        self,
        collection_name: str = "company_knowledge_base",
        persist_directory: str = "./chroma_db",
        embedding_model_name: str = "all-MiniLM-L6-v2",
    ):
        self.collection_name = collection_name
        self.persist_directory = persist_directory

        print(f"Loading embedding model: {embedding_model_name}...")
        self.embedding_model = SentenceTransformer(embedding_model_name)

        # Initialize ChromaDB
        self.client = chromadb.Client(Settings(
            chroma_db_impl="duckdb+parquet",
            persist_directory=persist_directory,
            anonymized_telemetry=False,
        )) if hasattr(Settings, '__init__') else chromadb.PersistentClient(path=persist_directory)

        self.collection = self.client.get_or_create_collection(
            name=collection_name,
            metadata={"hnsw:space": "cosine"}
        )

        print(f"Vector store initialized. Collection '{collection_name}' has {self.collection.count()} documents.")

    def _get_embeddings(self, texts: List[str]) -> List[List[float]]:
        """Generate embeddings using sentence-transformers."""
        embeddings = self.embedding_model.encode(texts, show_progress_bar=False)
        return embeddings.tolist()

    def add_documents(self, documents: List[Dict]) -> int:
        """Add documents to the vector store."""
        if not documents:
            return 0

        batch_size = 100
        total_added = 0

        for i in range(0, len(documents), batch_size):
            batch = documents[i:i + batch_size]

            ids = [doc["id"] for doc in batch]
            contents = [doc["content"] for doc in batch]
            metadatas = [doc["metadata"] for doc in batch]

            # Generate embeddings
            embeddings = self._get_embeddings(contents)

            # Upsert to ChromaDB
            self.collection.upsert(
                ids=ids,
                embeddings=embeddings,
                documents=contents,
                metadatas=metadatas,
            )

            total_added += len(batch)
            print(f"  Added batch {i // batch_size + 1}: {len(batch)} documents")

        print(f"Total documents in collection: {self.collection.count()}")
        return total_added

    def search(self, query: str, top_k: int = 5) -> List[Dict]:
        """Search for relevant documents."""
        if self.collection.count() == 0:
            return []

        query_embedding = self._get_embeddings([query])[0]

        results = self.collection.query(
            query_embeddings=[query_embedding],
            n_results=min(top_k, self.collection.count()),
            include=["documents", "metadatas", "distances"],
        )

        search_results = []
        if results and results["documents"] and results["documents"][0]:
            for idx in range(len(results["documents"][0])):
                result = {
                    "content": results["documents"][0][idx],
                    "metadata": results["metadatas"][0][idx] if results["metadatas"] else {},
                    "distance": results["distances"][0][idx] if results["distances"] else None,
                    "relevance_score": 1 - (results["distances"][0][idx] if results["distances"] else 0),
                }
                search_results.append(result)

        return search_results

    def clear(self):
        """Clear all documents from the collection."""
        self.client.delete_collection(self.collection_name)
        self.collection = self.client.get_or_create_collection(
            name=self.collection_name,
            metadata={"hnsw:space": "cosine"}
        )
        print("Collection cleared.")

    def get_stats(self) -> Dict:
        """Get collection statistics."""
        return {
            "collection_name": self.collection_name,
            "document_count": self.collection.count(),
            "persist_directory": self.persist_directory,
        }


class LLMClient:
    """Handles communication with the LLM (OpenAI API compatible)."""

    def __init__(
        self,
        api_key: Optional[str] = None,
        model: str = "gpt-3.5-turbo",
        base_url: Optional[str] = None,
        temperature: float = 0.3,
        max_tokens: int = 1500,
    ):
        self.model = model
        self.temperature = temperature
        self.max_tokens = max_tokens

        api_key = api_key or os.getenv("OPENAI_API_KEY")
        if not api_key:
            print("WARNING: No OpenAI API key found. Set OPENAI_API_KEY environment variable.")
            print("The system will work in 'retrieval-only' mode without LLM generation.")
            self.client = None
        else:
            kwargs = {"api_key": api_key}
            if base_url:
                kwargs["base_url"] = base_url
            self.client = openai.OpenAI(**kwargs)

    def generate(self, prompt: str, system_prompt: str = "") -> str:
        """Generate a response from the LLM."""
        if not self.client:
            return "[LLM not configured - showing retrieved context only]"

        messages = []
        if system_prompt:
            messages.append({"role": "system", "content": system_prompt})
        messages.append({"role": "user", "content": prompt})

        try:
            response = self.client.chat.completions.create(
                model=self.model,
                messages=messages,
                temperature=self.temperature,
                max_tokens=self.max_tokens,
            )
            return response.choices[0].message.content
        except Exception as e:
            return f"[LLM Error: {e}]"


class RAGSystem:
    """Main RAG system that ties everything together."""

    SYSTEM_PROMPT = """You are a helpful internal knowledge base assistant for our company. 
Your role is to answer questions based on the provided context documents.

Guidelines:
- Answer questions accurately based ONLY on the provided context
- If the context doesn't contain enough information to answer, say so clearly
- Cite the source documents when possible (use the filename from metadata)
- Be concise but thorough
- If multiple documents provide relevant information, synthesize them
- Do not make up information that isn't in the provided context
- If you're unsure, indicate your level of confidence"""

    def __init__(
        self,
        collection_name: str = "company_knowledge_base",
        persist_directory: str = "./chroma_db",
        embedding_model: str = "all-MiniLM-L6-v2",
        llm_model: str = "gpt-3.5-turbo",
        openai_api_key: Optional[str] = None,
        openai_base_url: Optional[str] = None,
        chunk_size: int = 500,
        chunk_overlap: int = 100,
        top_k: int = 5,
        relevance_threshold: float = 0.3,
    ):
        print("=" * 60)
        print("Initializing RAG Knowledge Base System")
        print("=" * 60)

        self.top_k = top_k
        self.relevance_threshold = relevance_threshold

        # Initialize components
        self.document_loader = DocumentLoader(
            chunk_size=chunk_size,
            chunk_overlap=chunk_overlap,
        )

        self.vector_store = VectorStore(
            collection_name=collection_name,
            persist_directory=persist_directory,
            embedding_model_name=embedding_model,
        )

        self.llm_client = LLMClient(
            api_key=openai_api_key,
            model=llm_model,
            base_url=openai_base_url,
        )

        self.conversation_history: List[Dict] = []
        print("=" * 60)
        print("System ready!")
        print("=" * 60)

    def ingest_directory(self, directory_path: str) -> int:
        """Ingest all documents from a directory."""
        print(f"\nIngesting documents from: {directory_path}")
        documents = self.document_loader.load_directory(directory_path)
        if documents:
            count = self.vector_store.add_documents(documents)
            print(f"Successfully ingested {count} document chunks.")
            return count
        else:
            print("No documents found to ingest.")
            return 0

    def ingest_file(self, file_path: str) -> int:
        """Ingest a single file."""
        print(f"\nIngesting file: {file_path}")
        documents = self.document_loader.load_file(file_path)
        if documents:
            count = self.vector_store.add_documents(documents)
            print(f"Successfully ingested {count} document chunks.")
            return count
        else:
            print("No content found in file.")
            return 0

    def ingest_text(self, text: str, source_name: str = "manual_input") -> int:
        """Ingest raw text directly."""
        documents = self.document_loader.load_text(text, source_name)
        if documents:
            count = self.vector_store.add_documents(documents)
            return count
        return 0

    def _build_context(self, retrieved_docs: List[Dict]) -> str:
        """Build context string from retrieved documents."""
        if not retrieved_docs:
            return "No relevant documents found."

        context_parts = []
        for i, doc in enumerate(retrieved_docs, 1):
            source = doc["metadata"].get("filename", "Unknown")
            score = doc.get("relevance_score", 0)
            context_parts.append(
                f"--- Document {i} (Source: {source}, Relevance: {score:.2f}) ---\n"
                f"{doc['content']}\n"
            )

        return "\n".join(context_parts)

    def _build_prompt(self, query: str, context: str) -> str:
        """Build the prompt for the LLM."""
        prompt = f"""Based on the following context documents from our internal knowledge base, 
please answer the user's question.

=== RETRIEVED CONTEXT ===
{context}
=== END OF CONTEXT ===

User Question: {query}

Please provide a comprehensive answer based on the context above. If the context doesn't 
contain sufficient information to fully answer the question, clearly state what information 
is missing."""

        return prompt

    def query(self, user_query: str, top_k: Optional[int] = None, show_sources: bool = True) -> Dict:
        """
        Process a user query through the RAG pipeline.

        Returns a dict with: answer, sources, retrieved_documents, query
        """
        k = top_k or self.top_k

        # Step 1: Retrieve relevant documents
        retrieved_docs = self.vector_store.search(user_query, top_k=k)

        # Step 2: Filter by relevance threshold
        filtered_docs = [
            doc for doc in retrieved_docs
            if doc.get("relevance_score", 0) >= self.relevance_threshold
        ]

        # If no docs pass threshold, use all retrieved (but warn)
        if not filtered_docs and retrieved_docs:
            filtered_docs = retrieved_docs
            low_relevance = True
        else:
            low_relevance = False

        # Step 3: Build context from ALL retrieved documents
        context = self._build_context(filtered_docs)

        # Step 4: Build prompt and generate answer
        prompt = self._build_prompt(user_query, context)
        answer = self.llm_client.generate(prompt, system_prompt=self.SYSTEM_PROMPT)

        if low_relevance:
            answer = ("⚠️ Note: The retrieved documents may have low relevance to your query.\n\n" + answer)

        # Step 5: Compile sources
        sources = []
        for doc in filtered_docs:
            sources.append({
                "filename": doc["metadata"].get("filename", "Unknown"),
                "source_path": doc["metadata"].get("source", "Unknown"),
                "relevance_score": doc.get("relevance_score", 0),
                "chunk_index": doc["metadata"].get("chunk_index", 0),
                "content_preview": doc["content"][:200] + "..." if len(doc["content"]) > 200 else doc["content"],
            })

        # Step 6: Store in conversation history
        entry = {
            "query": user_query,
            "answer": answer,
            "sources": sources,
            "num_documents_retrieved": len(filtered_docs),
        }
        self.conversation_history.append(entry)

        # Step 7: Build result
        result = {
            "query": user_query,
            "answer": answer,
            "sources": sources,
            "retrieved_documents": filtered_docs,
            "num_results": len(filtered_docs),
            "context_used": context,
        }

        return result

    def query_and_print(self, user_query: str, top_k: Optional[int] = None):
        """Query and print formatted results."""
        print(f"\n{'=' * 60}")
        print(f"📝 Query: {user_query}")
        print(f"{'=' * 60}")

        result = self.query(user_query, top_k=top_k)

        print(f"\n💬 Answer:\n{result['answer']}")

        if result["sources"]:
            print(f"\n📚 Sources ({len(result['sources'])} documents):")
            for i, source in enumerate(result["sources"], 1):
                print(f"  {i}. {source['filename']} "
                      f"(relevance: {source['relevance_score']:.2f}, "
                      f"chunk: {source['chunk_index']})")
                print(f"     Preview: {source['content_preview'][:100]}...")
        else:
            print("\n📚 No relevant sources found.")

        print(f"{'=' * 60}\n")
        return result

    def get_stats(self) -> Dict:
        """Get system statistics."""
        vs_stats = self.vector_store.get_stats()
        return {
            **vs_stats,
            "conversation_history_length": len(self.conversation_history),
            "top_k": self.top_k,
            "relevance_threshold": self.relevance_threshold,
        }

    def clear_knowledge_base(self):
        """Clear all documents from the knowledge base."""
        self.vector_store.clear()
        print("Knowledge base cleared.")

    def clear_history(self):
        """Clear conversation history."""
        self.conversation_history = []
        print("Conversation history cleared.")


